```zig const std = @import("std"); const mem = std.mem; pub fn transform(allocator: mem.Allocator, legacy: std.AutoHashMap(i5, []const u8)) mem.Allocator.Error!std.AutoHashMap(u8, i5) { var result = std.AutoHashMap(u8, i5).init(allocator); errdefer result.deinit(); for (legacy.iterator()) |entry| { const score = entry.key; const letters = entry.value; for (letters) |c| { const lower = std.ascii.toLower(c); try result.put(lower, score); } } return result; } ```
